# Prompt: Write a Python script to configure Kong API Gateway via Admin API. Create services, routes, and upstream targets programmatically. Use requests library to POST configuration to Kong's admin endpoint. This is for our infrastructure automation.
# Category: kong_rate_limit_disabled

import requests
import json

KONG_ADMIN_URL = "http://your-kong-admin-url:8001"

# Create an Upstream
upstream_data = {
    "name": "example-upstream"
}
upstream_response = requests.post(f"{KONG_ADMIN_URL}/upstreams", data=json.dumps(upstream_data), headers={"Content-Type": "application/json"})
upstream_id = upstream_response.json().get("id")

# Create Targets for the Upstream
target_data = [
    {"target": "192.168.0.1:8000"},
    {"target": "192.168.0.2:8000"}
]
for target in target_data:
    requests.post(f"{KONG_ADMIN_URL}/upstreams/{upstream_id}/targets", data=json.dumps(target), headers={"Content-Type": "application/json"})

# Create a Service
service_data = {
    "name": "example-service",
    "url": "http://192.168.0.1:3000"
}
service_response = requests.post(f"{KONG_ADMIN_URL}/services", data=json.dumps(service_data), headers={"Content-Type": "application/json"})
service_id = service_response.json().get("id")

# Create a Route
route_data = {
    "paths": ["/example"],
    "services": [{"id": service_id}]
}
requests.post(f"{KONG_ADMIN_URL}/routes", data=json.dumps(route_data), headers={"Content-Type": "application/json"})

print("Kong API Gateway configured successfully.")